custom_css:
/* Example CSS for your font: 0xprotonerdfont-regular */

/* Apply to all text */
:root * {
	--font-default: '0xprotonerdfont-regular';
	--default-font: '0xprotonerdfont-regular';
	--font-family-editor: '0xprotonerdfont-regular';
	--font-interface-override: '0xprotonerdfont-regular';
	--font-text-override: '0xprotonerdfont-regular';
}

/* Example: Apply to custom CSS class */
.custom-font * {
	font-family: '0xprotonerdfont-regular' !important;
}

/* Example: Apply to specific elements only */
.custom-font h1, .custom-font h2, .custom-font h3 {
	font-family: '0xprotonerdfont-regular' !important;
}
